return [{
  json: {
    config: {
      plataformaImportUrl: 'https://plataf-op-hml.vercel.app/api/comercial/hotmart/import',
      plataformaTenantId: 'ff24d2bc-22e2-4a5b-bc8c-f6d25a7fa3b0',
      n8nIngestToken: 'COLE_AQUI_O_MESMO_N8N_INGEST_TOKEN',
      hotmartBasicAuthorization: 'Basic COLE_AQUI_O_BASIC_DA_HOTMART',
      hotmartTokenUrl: 'https://api-sec-vlc.hotmart.com/security/oauth/token',
      hotmartSalesHistoryUrl: 'https://developers.hotmart.com/payments/api/v1/sales/history',
      startDate: '2020-01-01',
      endDate: new Date().toISOString().slice(0, 10),
      maxResults: 100,
      maxPages: 500
    },
    pageToken: null,
    pageNumber: 1
  }
}];

const tokenResponse = items[0]?.json || {};
const previous = $('Configurar Backfill').first().json;
const accessToken = tokenResponse.access_token || tokenResponse.token || tokenResponse.accessToken;

if (!accessToken) {
  throw new Error('Token Hotmart nao retornado. Confira hotmartBasicAuthorization no no Configurar Backfill.');
}

return [{
  json: {
    ...previous,
    accessToken
  }
}];

function get(obj, path) {
  return path.split('.').reduce((acc, key) => {
    if (!acc || typeof acc !== 'object') return undefined;
    return acc[key];
  }, obj);
}

function first(...values) {
  for (const value of values) {
    if (value !== undefined && value !== null && String(value).trim() !== '') return value;
  }
  return null;
}

function text(...values) {
  const value = first(...values);
  return value === null ? null : String(value).trim();
}

function number(...values) {
  const value = first(...values);
  if (value === null) return null;
  if (typeof value === 'number') return Number.isFinite(value) ? value : null;
  const normalized = String(value).replace(/\./g, '').replace(',', '.');
  const parsed = Number(normalized);
  return Number.isFinite(parsed) ? parsed : null;
}

function integer(...values) {
  const value = number(...values);
  return value ? Math.max(1, Math.round(value)) : 1;
}

function date(...values) {
  const value = first(...values);
  if (value === null) return null;
  const parsed = new Date(value);
  return Number.isNaN(parsed.getTime()) ? null : parsed.toISOString();
}

function statusFor(item) {
  return text(item.purchase_status, item.status, get(item, 'purchase.status'), get(item, 'data.purchase.status')) || 'unknown';
}

const response = items[0]?.json || {};
const context = $('Preparar Contexto').first().json;
const current = $('Buscar Historico Hotmart').first().json;
const candidates = [response.items, response.data, response.results, response.sales, response.purchases, response.content];
const sales = candidates.find(Array.isArray) || [];
const rows = [];

for (const item of sales) {
  const purchase = item.purchase || item;
  const buyer = item.buyer || purchase.buyer || {};
  const product = item.product || purchase.product || {};
  const payment = item.payment || purchase.payment || {};
  const price = purchase.price || item.price || {};
  const transactionId = text(purchase.transaction, item.transaction, item.transaction_id, item.id);
  const buyerEmail = text(buyer.email, item.buyer_email, item.email)?.toLowerCase();

  if (!transactionId || !buyerEmail) continue;

  rows.push({
    event_id: text(item.event_id, item.id, 'history-' + transactionId),
    transaction_id: transactionId,
    event: 'sales_history',
    product_id: text(product.id, product.ucode, item.product_id, item.hotmart_product_id),
    product_name: text(product.name, product.title, item.product_name, item.produto_nome),
    buyer_email: buyerEmail,
    buyer_name: text(buyer.name, buyer.full_name, item.buyer_name, item.name),
    buyer_phone: text(buyer.phone, buyer.phone_number, item.buyer_phone, item.telefone),
    status: statusFor(item),
    payment_type: text(payment.type, payment.method, purchase.payment_type, item.payment_type),
    installments: integer(payment.installments_number, payment.installments, purchase.installments_number, item.installments, item.parcelas),
    currency: text(price.currency_code, price.currency, item.currency, item.moeda) || 'BRL',
    gross_amount: number(price.value, purchase.price?.value, item.gross_amount, item.valor_bruto, item.price),
    net_amount: number(item.commission?.value, item.net_amount, item.valor_liquido),
    fees: number(item.fees?.value, purchase.fees?.value, item.fees, item.taxas),
    purchase_date: date(purchase.order_date, purchase.purchase_date, item.purchase_date, item.data_compra, item.creation_date),
    approved_date: date(purchase.approved_date, item.approved_date, item.data_aprovacao),
    refund_date: date(purchase.refund_date, item.refund_date, item.data_reembolso),
    chargeback_date: date(purchase.chargeback_date, item.chargeback_date, item.data_chargeback),
    expected_payment_date: date(item.receivable?.expected_payment_date, item.payment?.expected_payment_date, item.expected_payment_date, item.data_prevista),
    source_sck: text(item.tracking?.source_sck, purchase.tracking?.source_sck, item.source_sck, item.sck),
    raw_payload: item
  });
}

const nextPageToken = text(response.page_info?.next_page_token, response.pageInfo?.nextPageToken, response.next_page_token, response.nextPageToken, response.next);
const previousContext = current.accessToken ? current : context;
const pageNumber = Number(previousContext.pageNumber || 1);

return [{
  json: {
    ...previousContext,
    rows,
    count: rows.length,
    nextPageToken,
    hasNextPage: Boolean(nextPageToken) && pageNumber < Number(previousContext.config.maxPages || 200),
    pageNumber
  }
}];

const current = $('Normalizar Historico').first().json;
return [{
  json: {
    ...current,
    pageToken: current.nextPageToken,
    pageNumber: Number(current.pageNumber || 1) + 1
  }
}];
